// Normalize tracking event
let body = $input.item.json.body || $input.item.json;
if (typeof body === 'string') { try { body = JSON.parse(body); } catch(e) { body = {}; } }
body = body || {};
const headers = $input.item.json.headers || {};

function genRef() {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let r = '';
  for (let i = 0; i < 8; i++) r += chars[Math.floor(Math.random()*chars.length)];
  return r;
}

const lead_ref = body.lead_ref || genRef();

const payload = {
  lead_ref,
  session_id: body.session_id || null,
  event_type: body.event_type || 'unknown',
  page_path: body.page_path || null,
  landing_version: body.landing_version || null,
  gclid: body.gclid || null, gbraid: body.gbraid || null, wbraid: body.wbraid || null,
  fbclid: body.fbclid || null, msclkid: body.msclkid || null,
  utm_source: body.utm_source || null, utm_medium: body.utm_medium || null,
  utm_campaign: body.utm_campaign || null, utm_content: body.utm_content || null,
  utm_term: body.utm_term || null,
  utm_source_first: body.utm_source_first || null, utm_medium_first: body.utm_medium_first || null,
  utm_campaign_first: body.utm_campaign_first || null, utm_content_first: body.utm_content_first || null,
  utm_term_first: body.utm_term_first || null,
  referrer: body.referrer || null,
  time_on_page_ms: body.time_on_page_ms ?? null,
  scroll_depth_pct: body.scroll_depth_pct ?? null,
  user_agent: body.user_agent || headers['user-agent'] || null,
  device_type: body.device_type || null,
  screen_size: body.screen_size || null,
  language: body.language || null,
  timezone_offset: body.timezone_offset ?? null,
  ghl_contact_id: body.ghl_contact_id || null,
  extra: body.extra || {}
};
return { json: { payload, lead_ref } };
